function findTheDifference(s, t) {
    let sum_s = 0, sum_t = 0;
    for(let c of s) sum_s += c.charCodeAt(0);
    for(let c of t) sum_t += c.charCodeAt(0);
    return String.fromCharCode(sum_t - sum_s);
}
```

